mapper.select:
SELECT DISTINCT small_category AS value
FROM new_category
WHERE large_category = #{largeCategory}
AND medium_category = #{mediumCategory}
ORDER BY small_category

WITH sales_filtered AS ( SELECT s.order_date, s.order_number, s.platform, s.shipping_included, c.large_category, c.medium_category, c.small_category, s.product_total FROM new_sales_work_20260510 s LEFT JOIN new_product_work_20260510 p ON p.id = s.product_id LEFT JOIN new_category c ON c.id = p.category_id WHERE 1 = 1
AND s.order_date >= #{req.startDate}
AND s.order_date <= #{req.endDate}
AND c.large_category = #{req.largeCategory}
AND c.medium_category = #{req.mediumCategory}
AND c.small_category = #{req.smallCategory}
),
purchase_filtered AS ( SELECT pi.purchase_date, c.large_category, c.medium_category, c.small_category, pi.total_cost FROM new_purchase_info pi LEFT JOIN new_product_work_20260510 p ON p.id = pi.product_id LEFT JOIN new_category c ON c.id = p.category_id WHERE 1 = 1
AND pi.purchase_date >= #{req.startDate}
AND pi.purchase_date <= #{req.endDate}
AND c.large_category = #{req.largeCategory}
AND c.medium_category = #{req.mediumCategory}
AND c.small_category = #{req.smallCategory}
),
detail_rows AS ( SELECT sf.order_date AS dt, '매출' AS gb, sf.large_category, sf.medium_category, sf.small_category, SUM(sf.product_total) AS amount FROM sales_filtered sf GROUP BY sf.order_date, sf.large_category, sf.medium_category, sf.small_category
UNION ALL
SELECT pf.purchase_date AS dt, '매입' AS gb, pf.large_category, pf.medium_category, pf.small_category, SUM(pf.total_cost) AS amount FROM purchase_filtered pf GROUP BY pf.purchase_date, pf.large_category, pf.medium_category, pf.small_category ),
type_totals AS ( SELECT gb, SUM(amount) AS total_amount FROM detail_rows GROUP BY gb WITH ROLLUP HAVING gb IS NOT NULL ),
target_orders AS ( SELECT DISTINCT order_number, platform FROM sales_filtered WHERE shipping_included = 0 AND order_number IS NOT NULL ),
delivery_per_order AS ( SELECT d.order_number, d.platform, SUM(d.total_delivery_fee) AS total_delivery_fee FROM new_delivery_fee d WHERE d.shipping_included = 0 GROUP BY d.order_number, d.platform ),
deduct_fee AS ( SELECT COALESCE(SUM(dp.total_delivery_fee), 0) AS deducted_delivery_fee FROM delivery_per_order dp JOIN target_orders t ON t.order_number = dp.order_number AND t.platform = dp.platform ),
summary_rows AS ( SELECT NULL AS dt, '차감 택배비' AS gb, NULL AS large_category, NULL AS medium_category, NULL AS small_category, (SELECT deducted_delivery_fee FROM deduct_fee) AS amount, 1 AS summary_ord UNION ALL SELECT NULL, '매출합계', NULL, NULL, NULL, COALESCE((SELECT total_amount FROM type_totals WHERE gb = '매출'), 0), 2 UNION ALL SELECT NULL, '매입합계', NULL, NULL, NULL, COALESCE((SELECT total_amount FROM type_totals WHERE gb = '매입'), 0), 3 )
SELECT dt, gb, large_category, medium_category, small_category, amount FROM ( SELECT d.dt, d.gb, d.large_category, d.medium_category, d.small_category, d.amount, 0 AS grp, d.dt AS ord_date, FIELD(d.gb, '매출', '매입') AS ord_gb, 0 AS ord_summary FROM detail_rows d
UNION ALL
SELECT s.dt, s.gb, s.large_category, s.medium_category, s.small_category, s.amount, 1 AS grp, NULL AS ord_date, 0 AS ord_gb, s.summary_ord AS ord_summary FROM summary_rows s ) x ORDER BY x.grp, x.ord_date, x.ord_gb, x.large_category, x.medium_category, x.small_category, x.ord_summary
